import{o as p,c as e,D as t}from"./framework.02fa47e9.js";const a='{"title":"Глава 10","description":"","frontmatter":{"title":"Глава 10","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-09-01T00:00:00.000Z"},"headers":[{"level":2,"title":"Десятая глава","slug":"десятая-гnава"}],"relativePath":"texts/malini-vijayottara/10.md","lastUpdated":1624912907418}',r={},l=t('<h2 id="десятая-гnава"><a class="header-anchor" href="#десятая-гnава" aria-hidden="true">#</a> Десятая глава</h2><p>Теперь (поведаю) о лакхах (ста тысячах джап), наделяющих успехом в садхане. (Садхака должен обладать) знанием шастр, уравновешенностью, мудростью, неуязвимостью, правдивостью, стойкостью ..1.</p><p>Испытав садхаку (на эти качества) гуру должен укрепить (их). Совершив как подобает почитание Парамешвары как и раньше;.2.</p><p>Вторым (делом он должен установить), как и ранее, сосуд, сделанный из золота и прочего, без повреждений. Во всем (лотосе) в середине лотоса, или в южном лепестке, .3.</p><p>Следует почитать Наяков, с отдельной мантрой цветами и прочим. Выполнив тясячекратную тарпану, следует совершить абхишеку ..4.</p><p>В благоприятной бхадра питхе, у почитаемого дерева шрипарна, поместив (ученика?) лицом на восток или на север, омытого, украшенного цветами и прочим, .5.</p><p>Сотворенное тело мантры, производит благопритные (признаки). Звуки раковины барабана, и прочего, - известны как благоприятные звучащие признаки ..6.</p><p>С всеми царскими упачарами выполнив над ним абхишеку, созерцая его равным Садашиве, следует его украсить ..7.</p><p>Почтив вновь Владыку богов, пусть мудрый даст ему мантру. Пусть поместит (в его тело Ишвару, выполняя абхишеку) водой, цветами, зернами и маслом ..8.</p><p>Все это он должен вылить на голову ученику, приняв (образ) Дакшина мурти. Выполняя абхишеку с астра мантрой он должен явить Рудра Шакти ..9.</p><p>Благодаря им, объединившись с этой (мантрой), следует совершить тарпану тысячу раз. Тогда, настпупит начало, утверждение и объединение с нею ..10.</p><p>Без учителя , абхишеки, (<em>текст поврежден</em>) без правила мантры, как можно (выполнять) адхивасу (<em>текст поврежден</em>) ..11.</p><p>Обретя это труднодостижимое положение не достижимое самостоятельно, садхака, ради (обретения) совершенства в мантре (мантра сиддхи) должен следовать обету мантры ..12.</p><p>Совершив так названную абхишеку, совершив омовение, следует произносить джапу царственной видьи (<em>мантры</em>) сто тысяч раз. Десятую часть от этого (числа) следует совершить тарпану ..13.</p><p>Выполнив, как раньше, абхишеку, следует произносить джапу мантра шираса. Став наполненным обозначенным ею, следует (произносить джапу) два лакха (200 000), несмыкая глаз (без сна) ..14.</p><p>Две лакши (именуются) Рудрани, четыре - Пуруштута, пять лакхов, о Деви (именуются) Пашупата их следует произносить;.15.</p><p>Облачившись в белые, красные, желтые черные и пестрые одежды. Затем садхака защищенный мантрами примет образ (почитаемого божества) ..16.</p><p>Безмолвное произнесение (дает уничтожение) всех грехов усиление силы мантры. Приняв обет ее выпонения, желая практиковать ее;.17.</p><p>Поднеся аргхью, следует благоговейно произносить джапу девять лакхов. После хомы с высшей дравьей (следует выполнить) тарпану десятой частью (от этого числа) ..18.</p><p>(Подносится) мясо, которое именуют Великим владыкой земли, а также другие высшие дравьи, в середине (обряда), выполняя это два раза, три раза и или меньше ..19.</p><p>Масло гунгула (наделяет ) благосклонностью (любовью) женщин, равным ему считается великое мясо (<em>человечина</em>). Молоко, бильва, семена лотоса именуются несравненными на земле ..20.</p><p>Дхатри и дурва равны амрите, им же равным считается масло.</p><p>Следует выполнить затем (обряд) с маслом и прочим, 9, 6, 3 раз по порядку ..21.</p><p>Выполнив это прежде, пусть мудрый ради успеха (сиддхи) поднесет аргхью. Поднеся аргхью, пусть произносит джапу (в зависимости от того,) сколько он желает совершенств (сиддхи) ..22.</p><p>Благодарая одному лакху, Владыка земли приносит силу поддержания. Благодаря двум (лакхам), о Деви (садхака) обретет владычество и привлечение ..23.</p><p>Благодаря трем (лакхам) достигается умиротворение, благодаря четырем - достигается сила. Благодаря пяти -вся мудрость, благодаря шести -сонм гандхарвов ..24.</p><p>Благодаря семи -семь миров, благодаря десяти он станет равен им. Благодаря пятидесяти, он достигнет (состояния) за непроявленным, о Махешвари!.25.</p><p>За Майей, с шестью лакхами, за ишварой с восьмидесятью, благодаря десяти миллионам джап он обретет границу сакалы ..26.</p><p>Затем является сознание Виры, выполнив его. Все (все джапы) как было описано, в темную (половину месяца) днем или ночью, следует выполнять. (Таково) это правило ..27.</p><p>Выполнив описанное выше жертвоприношение, совершив наилучшее возлияние дравьи, пусть произносящий мантру выпрямив туловище, произносит джапу, не пошевелившись, (сидя) лицом на север;.28.</p><p>Выполняя (ее) до тех пор, пока не (проявится) целиком могущество йоги. (Когда он) выполнит (ее), (явится) беспорядочный шум, ужасный и чрезвычайно сильный ..29.</p><p>(Кто) упав на землю сможет подняться и устоять- тот Владыка садхаков. Выполнив для них поклон, отделив левую часть тела ..30.</p><p>И поднявшись к ним, поднеся аргьхю, станет равным им. Даже наставник должен выпоянть (джапу) каждый день сохраняя молчание в течении шести месяцев;.31.</p><p>(Практикуя) десять и пять мантр, которые были раньше названы мной Тебе; связанный предыдущей Ньясой, выполняя трижды (в день)огненный ритуал ..32.</p><p>Следует созерцать описанный выше трезубец, соблюдая брахмачарью, выполнив описанное выше жертвоприношение в окружении трех Шакти ..33.</p><p>Пусть учитель выполнит абхишеку над ним и над собой в начале и в конце. Став принявшим обет, он станет лучшим среди знающих мантру ..34.</p><p>Выполняющий обряды благословения и проклятия, он не может быть уязвим. Для его очищения следует поместить мула мантру, три раза по три ..34.</p><p>В левом большом пальце, ладони, глазах, указательных пальцах, в астре, с мечём А, КША ХРИМ, следует разместить шабдараши (алфавит) ..36.</p><p>(С мантрами) НА, ПХА, ХРИМ (размещаются) старательно образ Шакти. Обратная, махамудра, прайога и мула (мантра);.37.</p><p>В своих местах тела. Это именуется саманья ньясой. [small]Такова в священной «Малини виджайоттара тантре» десятая глава.[/small]</p>',40);r.render=function(t,a,r,i,m,s){return p(),e("div",null,[l])};export default r;export{a as __pageData};
